// Helper function to get a story by number
export const getStoryByNumber = (number: number): ChildrensBibleStory | undefined => {
  return childrensBibleStories.find(story => story.number === number);
};

// Helper function to get all stories
export const getAllStories = (): ChildrensBibleStory[] => {
  return childrensBibleStories;
};

// Helper function to get total story count
export const getTotalStories = (): number => {
  return childrensBibleStories.length;
};
